SELECT eixo1.chcatalogoguia AS chcatalogoguia,   eixo1.coddaunidadedeensino AS coddaunidadedeensino,   eixo1.codibgedolocaldaoferta AS codibgedolocaldaoferta,   CAST(eixo1.codigodocurso AS BIGINT) AS codigodocurso,   COUNT(DISTINCT eixo1.calculation838513981462429699) AS ctdcalculation838513981462429699ok,   eixo1.ead AS ead,   eixo1.eixotecnologicocatalogoguia AS eixotecnologicocatalogoguia,   eixo1.formaingresso AS formaingresso,   eixo1.municipiodolocaldaoferta AS municipiodolocaldaoferta,   eixo1.nodependenciaadmin AS nodependenciaadmin,   eixo1.nomodalidade AS nomodalidade,   eixo1.noparceirodemandante AS noparceirodemandante,   eixo1.nosistemaensino AS nosistemaensino,   eixo1.nomecursocatalogoguia AS nomecursocatalogoguia,   eixo1.nomedaue AS nomedaue,   eixo1.nomedauer AS nomedauer,   eixo1.subtipocurso AS subtipocurso,   eixo1.ufdolocaldaoferta AS ufdolocaldaoferta,   eixo1.unidadedemandante AS unidadedemandante,   CAST(EXTRACT(YEAR FROM eixo1.datadeinicio) AS BIGINT) AS yrdatadeiniciook FROM eixo1 WHERE ((CAST(EXTRACT(YEAR FROM eixo1.datadeinicio) AS BIGINT) IN (2013, 2014, 2015)) AND (NOT ((eixo1.nome_da_sit_matricula__situacao_detalhada_ IN ('CANC_DESISTENTE', 'CANC_MAT_PRIM_OPCAO', 'CANC_SANÇÃO', 'CANC_SEM_FREQ_INICIAL', 'CANC_TURMA', 'DOC_INSUFIC', 'ESCOL_INSUFIC', 'INC _ITINERARIO', 'INSC_CANC', 'Não Matriculado', 'NÃO_COMPARECEU', 'TURMA_CANC', 'VAGAS_INSUFIC')) OR (eixo1.nome_da_sit_matricula__situacao_detalhada_ IS NULL))) AND (NOT (eixo1.situacaodaturma IN ('CANCELADA', 'CRIADA', 'PUBLICADA')))) GROUP BY chcatalogoguia,   coddaunidadedeensino,   codibgedolocaldaoferta,   eixo1.codigodocurso,   ead,   eixotecnologicocatalogoguia,   formaingresso,   municipiodolocaldaoferta,   nodependenciaadmin,   nomodalidade,   noparceirodemandante,   nosistemaensino,   nomecursocatalogoguia,   nomedaue,   nomedauer,   subtipocurso,   ufdolocaldaoferta,   unidadedemandante,   yrdatadeiniciook,   codigodocurso;
